64	// payloadHash computes a content hash of the payload for idempotency.
65	func payloadHash(payload InjectPayload) (string, error) {
66		data, err := json.Marshal(payload)
67		if err != nil {
68			return "", fmt.Errorf("payload hash: marshal: %w", err)
69		}
70		sum := sha256.Sum256(data)
71		return hex.EncodeToString(sum[:]), nil
72	}
