83	// Inject creates or returns an idempotent bead of the specified kind.
84	// The bead is created with status=open if it doesn't already exist.
85	// Idempotency is based on (parent, kind, payload-hash).
86	// Parent must be a valid bead ID (will be validated against the store).
87	func (s *Store) Inject(ctx context.Context, parent string, payload InjectPayload, opts InjectOptions) (string, error) {
88		if parent == "" {
89			return "", fmt.Errorf("inject: parent bead ID required")
90		}
91		if payload == nil {
92			return "", fmt.Errorf("inject: payload required")
93		}
94		kind := payload.Kind()
95		if kind != IssueTypeReviewFinding && kind != IssueTypeAlignmentReview {
96			return "", fmt.Errorf("inject: unknown kind %q", kind)
97		}
98		if err := payload.Validate(); err != nil {
99			return "", fmt.Errorf("inject: %w", err)
100		}
101	
102		var foundID string
103		err := s.WithLock(func() error {
104			// Verify parent exists.
105			parentBead, err := s.Get(parent)
106			if err != nil {
107				return fmt.Errorf("inject: parent bead lookup failed: %w", err)
108			}
109			if parentBead == nil {
110				return fmt.Errorf("inject: parent bead not found: %s", parent)
111			}
112	
113			// Compute payload hash for idempotency.
114			hash, err := payloadHash(payload)
115			if err != nil {
116				return fmt.Errorf("inject: %w", err)
117			}
118	
119			// Check if an identical bead already exists.
120			allBeads, _, err := s.readAllLatestRaw()
121			if err != nil {
122				return fmt.Errorf("inject: read all beads failed: %w", err)
123			}
124	
125			for _, b := range allBeads {
126				if b.IssueType != kind || b.Parent != parent {
127					continue
128				}
129				// Check if the payload hash matches.
130				if existing, ok := b.Extra["payload_hash"]; ok && existing == hash {
131					foundID = b.ID
132					return nil
133				}
134			}
135	
136			// Create a new bead.
137			now := time.Now().UTC()
138			newID, err := s.GenID(context.Background())
139			if err != nil {
140				return fmt.Errorf("inject: generate id: %w", err)
141			}
142	
143			title := opts.Title
144			if title == "" {
145				title = fmt.Sprintf("%s: %s", kind, parent)
146			}
147	
148			priority := opts.Priority
149			if priority < 0 {
150				priority = 0
151			}
152			if priority > MaxPriority {
153				priority = MaxPriority
154			}
155	
156			newBead := &Bead{
157				ID:            newID,
158				Title:         title,
159				IssueType:     kind,
160				Status:        StatusOpen,
161				Priority:      priority,
162				SchemaVersion: CurrentSchemaVersion,
163				CreatedAt:     now,
164				UpdatedAt:     now,
165				Parent:        parent,
166				Description:   opts.Description,
167				Labels:        opts.Labels,
168				Extra: map[string]any{
169					"payload_hash": hash,
170					"payload":      payload,
171				},
172			}
173	
174			// Merge in any additional extra fields.
175			if opts.Extra != nil {
176				for k, v := range opts.Extra {
177					newBead.Extra[k] = v
178				}
179			}
180	
181			allBeads = append(allBeads, *newBead)
182			if err := s.WriteAll(allBeads); err != nil {
183				return fmt.Errorf("inject: write all: %w", err)
184			}
185	
186			foundID = newID
187			return nil
188		})
189		if err != nil {
190			return "", err
191		}
192		return foundID, nil
193	}
