91	// TestRunReviewFinding tests the review-finding dispatcher.
92	func TestRunReviewFinding(t *testing.T) {
93		ctx := context.Background()
94		mock := newMockBeadEventAppender()
95		now := func() time.Time { return time.Date(2026, 5, 21, 10, 0, 0, 0, time.UTC) }
96	
97		// Create a review-finding bead with payload.
98		reviewBead := &bead.Bead{
99			ID:        "review-001",
100			Title:     "Review Finding",
101			IssueType: bead.IssueTypeReviewFinding,
102			Status:    bead.StatusOpen,
103			Parent:    "parent-001",
104			CreatedAt: now(),
105			UpdatedAt: now(),
106			Extra: map[string]any{
107				"payload": map[string]interface{}{
108					"verdict":     "REQUEST_CHANGES",
109					"findings":    "Found issues in code",
110					"result_rev":  "abc123",
111					"reviewed_by": "alice",
112				},
113			},
114		}
115	
116		report, err := runReviewFinding(ctx, reviewBead.ID, reviewBead, mock, "/tmp", "ddx", now)
117		if err != nil {
118			t.Fatalf("runReviewFinding: %v", err)
119		}
120	
121		if report.Status != ExecuteBeadStatusSuccess {
122			t.Errorf("expected status=success, got %s", report.Status)
123		}
124		if report.Error != "" {
125			t.Errorf("expected no error, got %s", report.Error)
126		}
127	
128		// Verify event was appended.
129		events, ok := mock.events[reviewBead.ID]
130		if !ok || len(events) == 0 {
131			t.Fatalf("expected event to be appended, got none")
132		}
133		if events[0].Kind != "system-review-finding" {
134			t.Errorf("expected kind=system-review-finding, got %s", events[0].Kind)
135		}
